import{bQ as e,aL as r,u as d,G as a}from"./chunks/framework.D06dwy5q.js";const B=JSON.parse('{"title":"可观测性基础","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/01-可观测性基础.md","filePath":"12.可观测性与监控告警/01-可观测性基础.md","lastUpdated":null}'),o={name:"12.可观测性与监控告警/01-可观测性基础.md"};function E(h,t,c,l,s,i){return r(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="可观测性基础" tabindex="-1">可观测性基础 <a class="header-anchor" href="#可观测性基础" aria-label="Permalink to &quot;可观测性基础&quot;">​</a></h1><p>可观测性用来回答系统运行时到底发生了什么。线上接口开始超时、用户反馈慢、发布后错误率升高——这些场景需要的不只是打开 Grafana 看一眼 CPU 曲线。</p><p>实践中通常看四类信息：指标看趋势和异常，日志看每次请求的具体报错，链路追踪看一次请求经过了哪些服务、慢在哪一段，事件看异常前后有没有发布、重启或配置变更。四类信号合在一起，才能从&quot;CPU 正常&quot;推进到&quot;具体哪里出了什么问题&quot;。</p><h2 id="四类信号" tabindex="-1">四类信号 <a class="header-anchor" href="#四类信号" aria-label="Permalink to &quot;四类信号&quot;">​</a></h2><p>指标是带时间戳的数值。CPU 使用率、内存可用量、磁盘剩余空间、接口 QPS、接口延迟（通常看 P95——95% 的请求比这个值快，剩下 5% 比它慢）、错误率、MySQL 连接数、Redis 命中率，都属于指标。因为格式统一，适合画曲线、做聚合、设告警阈值。指标回答的问题是&quot;现在是否异常&quot;和&quot;趋势是否变坏&quot;。不适合回答&quot;单次请求为什么失败&quot;——这是日志的范畴。</p><p>日志是系统或应用写出的文本记录，通常包含时间戳、级别、来源和具体内容。错误堆栈、请求参数、SQL 语句、业务错误码、用户 ID 这些细节，指标存不下，日志可以。线上排查时常见的用法是：先在指标上发现某个服务错误率升高了，再到日志里按服务名和时间范围过滤，看具体报错内容。日志里的关键字段（<code>service</code>、<code>env</code>、<code>trace_id</code>、<code>status</code>、<code>level</code>）设计得好，可以快速过滤出相关行。</p><p>链路追踪记录一次请求经过了哪些服务、每一段花了多少时间、错误出在哪个调用上。一个 Web 请求进来 → 订单服务 → 用户服务 → 订单服务读 MySQL → 调 Redis 缓存，整个过程跨多个服务，Trace 把这条调用链串成一棵树，每段叫一个 Span。指标上看到 P95 延迟尖刺时，如果 Trace 里显示&quot;订单服务 → MySQL 查询&quot;这一段耗时占比 95%，排查方向就能收窄到具体 SQL。</p><p>事件记录系统状态变化——发布、扩容、重启、配置变更、节点 NotReady、告警触发、告警恢复都属于事件。排查时经常先看指标异常出现的时间点，再去对照那段时间有没有发布或变更。用发布记录、审计日志、Kubernetes Events 来补时间线。</p><table tabindex="0"><thead><tr><th>信号</th><th>常见内容</th><th>更适合回答的问题</th></tr></thead><tbody><tr><td>Metrics</td><td>CPU、内存、磁盘、QPS、延迟、错误率</td><td>是否异常，趋势是否变坏</td></tr><tr><td>Logs</td><td>应用日志、系统日志、访问日志、错误堆栈</td><td>当时具体报了什么</td></tr><tr><td>Traces</td><td>Trace、Span、调用关系、单段耗时</td><td>慢请求卡在哪个服务或哪次数据库调用</td></tr><tr><td>Events</td><td>发布、重启、扩容、告警触发、告警恢复</td><td>异常前后发生了什么变化</td></tr></tbody></table><h2 id="排查链路" tabindex="-1">排查链路 <a class="header-anchor" href="#排查链路" aria-label="Permalink to &quot;排查链路&quot;">​</a></h2><p>接口超时时，一个常见的排查顺序是：</p><ol><li>先看指标——错误率和 P95 是不是在升高？全局的还是某个服务的？</li><li>再看事件——刚才有没有发布、重启或配置变更？</li><li>指标指向某个服务后，看它的日志——错误堆栈报了什么？</li><li>日志指向某次调用很慢，看链路追踪——慢在 MySQL、Redis 还是下游 HTTP？</li></ol><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20alert%5B%22%E5%91%8A%E8%AD%A6%3Cbr%2F%3E%E6%8E%A5%E5%8F%A3%E5%BB%B6%E8%BF%9F%E5%8D%87%E9%AB%98%22%5D%20--%3E%20metrics%5B%22%E6%8C%87%E6%A0%87%3Cbr%2F%3EQPS%20%2F%20%E9%94%99%E8%AF%AF%E7%8E%87%20%2F%20P95%22%5D%0A%20%20%20%20metrics%20--%3E%20logs%5B%22%E6%97%A5%E5%BF%97%3Cbr%2F%3E%E9%94%99%E8%AF%AF%E5%A0%86%E6%A0%88%20%2F%20%E8%AF%B7%E6%B1%82%E5%AD%97%E6%AE%B5%22%5D%0A%20%20%20%20metrics%20--%3E%20traces%5B%22%E9%93%BE%E8%B7%AF%3Cbr%2F%3E%E6%85%A2%E8%B0%83%E7%94%A8%20%2F%20%E4%B8%8B%E6%B8%B8%E4%BE%9D%E8%B5%96%22%5D%0A%20%20%20%20alert%20--%3E%20events%5B%22%E4%BA%8B%E4%BB%B6%3Cbr%2F%3E%E5%8F%91%E5%B8%83%20%2F%20%E6%89%A9%E5%AE%B9%20%2F%20%E9%85%8D%E7%BD%AE%E5%8F%98%E6%9B%B4%22%5D%0A%20%20%20%20logs%20--%3E%20result%5B%22%E5%AE%9A%E4%BD%8D%E5%8E%9F%E5%9B%A0%22%5D%0A%20%20%20%20traces%20--%3E%20result%0A%20%20%20%20events%20--%3E%20result%0A"></div><p>这四类不用一次性全搭好。从指标告警开始——先知道什么时候出了问题；再补关键服务的日志采集——能查到报了什么错；链路追踪放到后面慢慢补——能还原慢请求的内部调用路径。</p><h2 id="prometheus-体系的指标链路" tabindex="-1">Prometheus 体系的指标链路 <a class="header-anchor" href="#prometheus-体系的指标链路" aria-label="Permalink to &quot;Prometheus 体系的指标链路&quot;">​</a></h2><p>Prometheus 负责指标采集、存储和告警规则计算。整个流程分四段：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20app%5B%22%E5%BA%94%E7%94%A8%20%2F%20%E7%B3%BB%E7%BB%9F%E7%BB%84%E4%BB%B6%22%5D%20--%3E%20exporter%5B%22Exporter%3Cbr%2F%3E%E6%9A%B4%E9%9C%B2%20%2Fmetrics%22%5D%0A%20%20%20%20prometheus%5B%22Prometheus%3Cbr%2F%3E%E5%AE%9A%E6%97%B6%E6%8A%93%E5%8F%96%E6%8C%87%E6%A0%87%22%5D%20--%3E%20exporter%0A%20%20%20%20prometheus%20--%3E%20tsdb%5B%22%E6%9C%AC%E5%9C%B0%20TSDB%3Cbr%2F%3E%E4%BF%9D%E5%AD%98%E6%97%B6%E9%97%B4%E5%BA%8F%E5%88%97%22%5D%0A%20%20%20%20prometheus%20--%3E%20rules%5B%22%E5%91%8A%E8%AD%A6%E8%A7%84%E5%88%99%3Cbr%2F%3E%E8%AE%A1%E7%AE%97%20firing%20%2F%20resolved%22%5D%0A%20%20%20%20rules%20--%3E%20alertmanager%5B%22Alertmanager%3Cbr%2F%3E%E5%88%86%E7%BB%84%20%2F%20%E9%9D%99%E9%BB%98%20%2F%20%E8%B7%AF%E7%94%B1%22%5D%0A%20%20%20%20prometheus%20--%3E%20grafana%5B%22Grafana%3Cbr%2F%3E%E6%9F%A5%E8%AF%A2%E5%92%8C%E7%9C%8B%E6%9D%BF%22%5D%0A"></div><p>Exporter 把系统状态转成 Prometheus 认识的指标格式，暴露在 <code>/metrics</code> 路径上。Prometheus 按照配置文件里的地址定时去抓取，抓回来的样本写进本地 TSDB（时序数据库）。TSDB 针对按时间范围查询做了优化——查&quot;最近 5 分钟 CPU&quot;和&quot;昨天下午 2 点到 3 点的 QPS&quot;都很快。告警规则按固定间隔计算，如果一条规则持续满足条件（比如 CPU 连续高于 90%），就把状态变为 firing，推给 Alertmanager。Alertmanager 负责分组、静默、抑制和路由——多条告警要不要合成一条、维护窗口期间是否静默、按什么条件发给谁。</p><p>链路中的几个基本对象：</p><table tabindex="0"><thead><tr><th>名词</th><th>说明</th><th>排查时看什么</th></tr></thead><tbody><tr><td>Exporter</td><td>把系统状态转成 Prometheus 可抓的指标</td><td>端口是否通，<code>/metrics</code> 是否有内容</td></tr><tr><td>Target</td><td>Prometheus 实际抓取的地址</td><td>Targets 页面是否 <code>UP</code></td></tr><tr><td>Scrape</td><td>Prometheus 定时去抓取一次的动作</td><td>最近一次抓取时间和耗时</td></tr><tr><td>TSDB</td><td>Prometheus 本地时序数据库</td><td>保留周期、磁盘用量、查询性能</td></tr><tr><td>Label</td><td>指标上的键值标签</td><td>按实例、服务、环境等维度聚合</td></tr><tr><td>Rule</td><td>定时计算的告警规则</td><td>表达式是否能查到异常序列</td></tr><tr><td>Alertmanager</td><td>接收告警，负责分组、静默、抑制、通知</td><td>告警是否到了正确的接收人</td></tr></tbody></table><p>Prometheus 默认是 Pull 模型——主动去各个目标抓指标，而不是等别人推过来。这意味着 Targets 页面能直接看到每个目标的最后一次抓取是否成功。某个目标出问题时，在 Prometheus 所在机器上 <code>curl http://目标:端口/metrics</code> 就能验证到 exporter 的网络和端口。短生命周期任务（定时备份脚本跑几秒就退出）用 Pull 可能等不到下次抓取，这类场景可以用 Pushgateway 作为补充中转。</p><h2 id="实验环境" tabindex="-1">实验环境 <a class="header-anchor" href="#实验环境" aria-label="Permalink to &quot;实验环境&quot;">​</a></h2><p>三台 Rocky Linux 9.7：</p><table tabindex="0"><thead><tr><th>主机</th><th>角色</th><th>组件</th></tr></thead><tbody><tr><td><code>192.168.10.11</code></td><td>监控节点</td><td>Prometheus、Alertmanager、Grafana、Node Exporter</td></tr><tr><td><code>192.168.10.12</code></td><td>被监控节点</td><td>Node Exporter</td></tr><tr><td><code>192.168.10.13</code></td><td>被监控节点</td><td>Node Exporter</td></tr></tbody></table><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20p%5B%22Prometheus%3Cbr%2F%3E192.168.10.11%3A9090%22%5D%20--%3E%20n1%5B%22Node%20Exporter%3Cbr%2F%3E192.168.10.11%3A9100%22%5D%0A%20%20%20%20p%20--%3E%20n2%5B%22Node%20Exporter%3Cbr%2F%3E192.168.10.12%3A9100%22%5D%0A%20%20%20%20p%20--%3E%20n3%5B%22Node%20Exporter%3Cbr%2F%3E192.168.10.13%3A9100%22%5D%0A%20%20%20%20p%20--%3E%20am%5B%22Alertmanager%3Cbr%2F%3E192.168.10.11%3A9093%22%5D%0A%20%20%20%20g%5B%22Grafana%3Cbr%2F%3E192.168.10.11%3A3000%22%5D%20--%3E%20p%0A"></div><p>这个环境覆盖从指标采集到告警通知的最短链路：主机指标采回来 → 写进 TSDB → PromQL 查询 → Grafana 看板 → 告警规则 → Alertmanager 通知。</p><h2 id="dashboard-和-alert-的分工" tabindex="-1">Dashboard 和 Alert 的分工 <a class="header-anchor" href="#dashboard-和-alert-的分工" aria-label="Permalink to &quot;Dashboard 和 Alert 的分工&quot;">​</a></h2><p>看板是人主动去看的，告警是平台主动通知人的。看板上的指标可以放多一些——排查和观察时越全越好。告警规则要更克制，一条规则要能回答三个问题才算值得设：异常能被指标稳定表达吗、持续一段时间后还在吗、需要人来处理吗。磁盘 90% 满足这三条——很快就满了，不会自动缩小，人要去清或扩容。CPU 偶发冲到 80% 经常不满足——瞬间就回去了，放在看板上观察更合适。</p><table tabindex="0"><thead><tr><th>对象</th><th>用法</th></tr></thead><tbody><tr><td>Dashboard</td><td>排查和观察，指标可以多一些</td></tr><tr><td>Alert</td><td>发现需要处理的问题，规则要少而准</td></tr><tr><td>Runbook</td><td>告警后的检查步骤，几句话给出排查方向</td></tr><tr><td>Event</td><td>还原异常前后的发布、变更、重启记录</td></tr></tbody></table><p>告警发太多是常见问题——十几条类似通知刷屏，值班的人慢慢就会习惯性忽略，一直忽略到真正重要的那条也漏掉。</p><h2 id="四类信号的关联" tabindex="-1">四类信号的关联 <a class="header-anchor" href="#四类信号的关联" aria-label="Permalink to &quot;四类信号的关联&quot;">​</a></h2><p>指标、日志、链路追踪靠几个公共字段关联：</p><table tabindex="0"><thead><tr><th>关联字段</th><th>作用</th></tr></thead><tbody><tr><td><code>service</code></td><td>指标、日志、Trace 都按服务名过滤</td></tr><tr><td><code>env</code> / <code>cluster</code></td><td>区分环境和集群</td></tr><tr><td><code>instance</code> / <code>pod</code></td><td>定位具体运行实例</td></tr><tr><td><code>trace_id</code></td><td>从日志跳到 Trace，或从 Trace 反向找关联日志</td></tr><tr><td>exemplar</td><td>从指标曲线上的异常点跳到对应的 Trace</td></tr></tbody></table><p>Grafana 上看到一个 P95 尖刺，通过 exemplar 跳到几条代表性的慢 Trace，再拿着这些 TraceID 去日志里搜请求详情——这个关联能省掉&quot;从指标发现异常 → 去日志系统按时间范围手工翻&quot;的步骤。这个系列按&quot;先搭指标和告警，再补日志和 Trace&quot;的节奏展开。</p>',34)])])}const p=e(o,[["render",E]]);export{B as __pageData,p as default};
